export const getGetTenantDashboardQueryKey = (slug: string) => {
  return [`/api/tenants/${slug}/dashboard`] as const;
};

export const getGetTenantDashboardQueryOptions = <
  TData = Awaited<ReturnType<typeof getTenantDashboard>>,
  TError = ErrorType<unknown>,
>(
  slug: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getTenantDashboard>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetTenantDashboardQueryKey(slug);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getTenantDashboard>>
  > = ({ signal }) => getTenantDashboard(slug, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!slug,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getTenantDashboard>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetTenantDashboardQueryResult = NonNullable<
  Awaited<ReturnType<typeof getTenantDashboard>>
>;
export type GetTenantDashboardQueryError = ErrorType<unknown>;

/**
 * @summary Get dashboard summary stats for a tenant
 */

export function useGetTenantDashboard<
  TData = Awaited<ReturnType<typeof getTenantDashboard>>,
  TError = ErrorType<unknown>,
>(
  slug: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getTenantDashboard>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetTenantDashboardQueryOptions(slug, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
